def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        score = 0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0.1:
            base = np.exp(-ratio * 20) + np.log1p(ratio * 50)
            for k in range(1, 6):
                base += ((-1) ** k) * (ratio ** (k * 2)) / (k + 0.1)
            priorities[i] = base * 15
            if capacity < item * 0.5:
                priorities[i] *= (item / capacity) * 0.8
        elif 0.1 <= ratio < 0.5:
            primes = [2, 3, 5, 7, 11]
            temp_score = 0
            for idx, p in enumerate(primes):
                temp_score += ((-1) ** idx) * (ratio ** p) / (p * 1.2)
            for z in range(1, 4):
                temp_score += ((ratio ** z) / (z + 0.3)) ** 1.5
            priorities[i] = abs(temp_score) * 20
            if capacity == item:
                priorities[i] += 7
        elif 0.5 <= ratio <= 1.2:
            factorial = 1
            for f in range(1, 5):
                factorial *= f
            sum1 = 0
            for m in range(1, 10):
                sign = 1 if m % 2 else -1
                sum1 += sign * (ratio ** m) / (m ** 1.1 + 0.5)
            sum2 = 0
            for n in range(1, 6):
                sum2 += (ratio ** (n / 2)) / (n + 1)
            priorities[i] = (abs(sum1) + sum2) * factorial / 5
            if 0.9 < ratio < 1.0:
                priorities[i] += 10 * (1 - abs(capacity - item) / capacity)
        else:
            penalty = 0
            for p in range(1, 7):
                penalty += (ratio ** (p * 1.3)) / (p * 2 + 0.7)
            if capacity > item * 3:
                priorities[i] = penalty / (capacity / item) ** 1.5
            else:
                priorities[i] = penalty * (capacity / item)
            if ratio > 2.5:
                priorities[i] += np.tanh((ratio - 2.5) * 3) * 20
            if ratio > 3.0 and capacity < item * 4:
                priorities[i] += 30 / (capacity / item)
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
